const papers = items[0].json.message.items;
return papers.map(paper => ({
  json: {
    title: paper.title ? paper.title[0] : "",
    authors: paper.author ? paper.author.map(a => `${a.given} ${a.family}`).join(", ") : "",
    publishedDate: paper.published ? paper.published['date-parts'][0].join('-') : "",
    doi: paper.DOI || "",
    url: paper.URL || "",
    abstract: paper.abstract || ""
  }
}));

return items.map(item => {
  const analysis = item.json.choices && item.json.choices[0] ? item.json.choices[0].message.content : '';
  return {
    json: {
      title: item.json.title,
      authors: item.json.authors,
      publishedDate: item.json.publishedDate,
      doi: item.json.doi,
      url: item.json.url,
      impactAnalysis: analysis
    }
  };
});

/* 
  Identify potential collaboration opportunities by matching overlapping authors,
  keywords, or institutions from the aggregated papers.
  For demo, assume sending to Slack channel and also prepare collaboration invites.
*/

const collaborations = [];

// Simple example: group papers by author to find overlapping authors
const authorMap = {};

for (const item of items) {
  const authors = item.json.authors.split(", ");
  for (const author of authors) {
    if (!authorMap[author]) authorMap[author] = [];
    authorMap[author].push({ title: item.json.title, url: item.json.url });
  }
}

for (const author in authorMap) {
  if (authorMap[author].length > 1) {
    collaborations.push({
      author,
      papers: authorMap[author]
    });
}
}

return collaborations.length
  ? [{ json: { collaborations } }]
  : [{ json: { collaborations: "No immediate collaboration opportunities found." } }];

/* Generate innovation insights summary report from paper impact analyses and collaboration opportunities. */

const papersAnalysis = items[0].json.map(paper => `- Title: ${paper.title}\n  Impact & Relevance: ${paper.impactAnalysis}`);

const collaborations = items[1].json.collaborations;

let collaborationSummary = '';
if (collaborations === "No immediate collaboration opportunities found.") {
  collaborationSummary = 'No collaboration opportunities found based on current dataset.';
} else {
  collaborationSummary = collaborations.map(c => `* ${c.author} involved in papers: ${c.papers.map(p => p.title).join('; ')}`).join('\n');
}

const report = `Quantum Computing Research Innovation Insights Report\n\nResearch Papers Analysis:\n${papersAnalysis.join('\n\n')}\n\nCollaboration Opportunities:\n${collaborationSummary}`;

return [{ json: { report } }];
